    33	/**
    34	 * Forbids instantiation of certain object types by their full classname. <br>
    35	 * <p>
    36	 * For example:<br>
    37	 * "java.lang.NullPointerException" will forbid the NPE instantiation.
    38	 * </p>
    39	 * <p>
    40	 * Note: className should to be full: use "java.lang.NullPointerException"
    41	 * instead of "NullpointerException".
    42	 * </p>
    43	 * @author <a href="mailto:Daniil.Yaroslavtsev@gmail.com"> Daniil
    44	 *         Yaroslavtsev</a>
    45	 */
    46	public class ForbidInstantiationCheck extends AbstractCheck {
    47	
    48	    /**
    49	     * A key is pointing to the warning message text in "messages.properties"
    50	     * file.
    51	     */
    52	    public static final String MSG_KEY = "forbid.instantiation";
    53	
    54	    /** Path string to separate layers of packages. */
    55	    private static final String PATH_SEPARATOR = ".";
    56	
    57	    /**
    58	     * Set which contains classNames for objects that are forbidden to
    59	     * instantiate.
    60	     */
    61	    private Set<String> forbiddenClasses = new HashSet<>();
    62	
    63	    /**
    64	     * List which contains String representation of imports for class is
    65	     * currently being processed.
    66	     */
    67	    private List<String> importsList = new LinkedList<>();
    68	
    69	    /**
    70	     * Creates the check instance.
    71	     */
    72	    public ForbidInstantiationCheck() {
    73	        forbiddenClasses.add("java.lang.NullPointerException");
    74	    }
    75	
    76	    /**
    77	     * Sets a classNames&amp;Paths for objects that are forbidden to instantiate.
    78	     * @param classNames
    79	     *        - the list of classNames separated by a comma. ClassName should be
    80	     *        full, such as "java.lang.NullpointerException", do not use short
    81	     *        name - NullpointerException;
    82	     */
    83	    public void setForbiddenClasses(final String[] classNames) {
    84	        forbiddenClasses.clear();
    85	        if (classNames != null) {
    86	            for (String name : classNames) {
    87	                forbiddenClasses.add(name);
    88	            }
    89	        }
    90	    }
    91	
    92	    @Override
    93	    public void beginTree(final DetailAST rootAST) {
    94	        importsList.clear();
    95	    }
    96	
    97	    @Override
    98	    public int[] getDefaultTokens() {
    99	        return new int[] {TokenTypes.IMPORT, TokenTypes.LITERAL_NEW };
   100	    }
   101	
   102	    @Override
   103	    public int[] getAcceptableTokens() {
   104	        return getDefaultTokens();
   105	    }
   106	
   107	    @Override
   108	    public int[] getRequiredTokens() {
   109	        return getDefaultTokens();
   110	    }
   111	
   112	    @Override
   113	    public void visitToken(DetailAST ast) {
   114	        switch (ast.getType()) {
   115	            case TokenTypes.IMPORT:
   116	                importsList.add(getText(ast));
   117	                break;
   118	
   119	            case TokenTypes.LITERAL_NEW:
   120	
   121	                final String instanceClass = getText(ast);
   122	
   123	                if (instanceClass != null) {
   124	                    // non-primitive instance
   125	
   126	                    final String instanceClassName = getClassName(instanceClass);
   127	
   128	                    for (String forbiddenClass : forbiddenClasses) {
   129	                        if (forbiddenClass.startsWith("java.lang.")
   130	                            && forbiddenClass.endsWith(instanceClassName)) {
   131	                            log(ast, MSG_KEY, instanceClassName);
   132	                        }
   133	                        else if (instanceClass.contains(PATH_SEPARATOR)) {
   134	                            // className is full
   135	
   136	                            if (instanceClass.equals(forbiddenClass)) {
   137	                                // the full path is forbidden
   138	                                log(ast, MSG_KEY, instanceClassName);
   139	                            }
   140	                        }
   141	                        else if (addedUsingForbiddenImport(instanceClass,
   142	                            forbiddenClass)) {
   143	                            // className is short and exists in imports
   144	                            log(ast, MSG_KEY, instanceClass);
   145	                        }
   146	                    }
   147	                }
   148	                break;
   149	
   150	            default:
   151	                Utils.reportInvalidToken(ast.getType());
   152	                break;
   153	        }
   154	    }
   155	
   156	    /**
   157	     * Checks that the class with given className is visible because of the
   158	     * forbidden import.
   159	     * @param className
   160	     *        - the name of the class to check.
   161	     * @param forbiddenClassNameAndPath
   162	     *        - full name&path of the given forbidden class.
   163	     * @return true if the class with given className is imported with the
   164	     *         forbidden import and false otherwise.
   165	     */
   166	    private boolean addedUsingForbiddenImport(final String className,
   167	            String forbiddenClassNameAndPath) {
   168	        boolean result = false;
   169	
   170	        for (String importText : importsList) {
   171	            if (isWildcardForbiddenImported(importText, forbiddenClassNameAndPath, className)
   172	                    || isForbiddenImported(importText, forbiddenClassNameAndPath, className)) {
   173	                result = true;
   174	                break;
   175	            }
   176	        }
   177	
   178	        return result;
   179	    }
   180	
   181	    /**
   182	     * Tests if the class with given className is imported with the forbidden
   183	     * import and false otherwise.
   184	     *
   185	     * @param importText
   186	     *        - String representation of imports from the processed class.
   187	     * @param className
   188	     *        - the name of the class to check.
   189	     * @param forbiddenClassNameAndPath
   190	     *        - full name&path of the given forbidden class.
   191	     * @return true if the class with given className is imported with the
   192	     *         forbidden import and false otherwise.
   193	     */
   194	    private static boolean isWildcardForbiddenImported(String importText,
   195	            String forbiddenClassNameAndPath, String className) {
   196	        final String importTextWithoutAsterisk =
   197	                importText.substring(0, importText.length() - 1);
   198	
   199	        return importText.endsWith("*")
   200	                && (importTextWithoutAsterisk + className).equals(forbiddenClassNameAndPath);
   201	    }
   202	
   203	    /**
   204	     * Tests if the class with given className is imported with the forbidden
   205	     * import and false otherwise.
   206	     *
   207	     * @param importText
   208	     *        - String representation of imports from the processed class.
   209	     * @param className
   210	     *        - the name of the class to check.
   211	     * @param forbiddenClassNameAndPath
   212	     *        - full name&path of the given forbidden class.
   213	     * @return true if the class with given className is imported with the
   214	     *         forbidden import and false otherwise.
   215	     */
   216	    private static boolean isForbiddenImported(String importText, String forbiddenClassNameAndPath,
   217	            String className) {
   218	        return importText.equals(forbiddenClassNameAndPath)
   219	                && importText.endsWith(className);
   220	    }
   221	
   222	    /**
   223	     * Gets the class name from full (dotted) classPath.
   224	     * @param classNameAndPath
   225	     *        - the full (dotted) classPath
   226	     * @return the name of the class is specified by the current full name&path.
   227	     */
   228	    private static String getClassName(final String classNameAndPath) {
   229	        return classNameAndPath.replaceAll(".+\\.", "");
   230	    }
   231	
   232	    /**
   233	     * Gets the text representation from the given DetailAST node.
   234	     * @param ast
   235	     *        - DetailAST node is pointing to import definition or to the "new"
   236	     *        literal node ("IMPORT" or "LITERAL_NEW" node types).
   237	     * @return Import text without "import" word and semicolons for given
   238	     *         "IMPORT" node or instanstiated class Name&Path for given
   239	     *         "LITERAL_NEW" node.
   240	     */
   241	    private static String getText(final DetailAST ast) {
   242	        String result = null;
   243	
   244	        final DetailAST textWithoutDots = ast.findFirstToken(TokenTypes.IDENT);
   245	
   246	        if (textWithoutDots == null) {
   247	            // if there are TokenTypes.DOT nodes in subTree.
   248	            final DetailAST parentDotAST = ast.findFirstToken(TokenTypes.DOT);
   249	            if (parentDotAST != null) {
   250	                final FullIdent dottedPathIdent = FullIdent
   251	                        .createFullIdentBelow(parentDotAST);
   252	                final DetailAST nameAST = parentDotAST.getLastChild();
   253	                result = dottedPathIdent.getText() + PATH_SEPARATOR + nameAST.getText();
   254	            }
   255	        }
   256	        // if subtree doesn`t contain dots.
   257	        else {
   258	            result = textWithoutDots.getText();
   259	        }
   260	        return result;
   261	    }
   262	
   263	}
