    30	/**
    31	 * <p>Forbids certain imports usage in certain packages.
    32	 * </p>
    33	 * You can configure this check using the following parameters:
    34	 * <ol>
    35	 * <li>Package qualified name regexp;</li>
    36	 * <li>Forbidden imports regexp;</li>
    37	 * <li>Forbidden imports excludes regexp.</li>
    38	 * </ol>
    39	 * <p>
    40	 * This check loads packages qualified names without
    41	 * words "package","import" and semicolons, so, please, do NOT include "package" or
    42	 * "import" words (or semicolons) into config regexps.</p>
    43	 * <p>
    44	 * Real-life example of usage: forbid to use all "*.ui.*" packages in "*.dao.*" packages,
    45	 * but ignore all Exception imports (such as
    46	 * <b>org.springframework.dao.InvalidDataAccessResourceUsageException</b>).
    47	 * For doing that, you should to use the following check parameters:
    48	 * </p>
    49	 * <ul>
    50	 * <li>Package name regexp = ".*ui.*"</li>
    51	 * <li>Forbidden imports regexp = ".*dao.*"</li>
    52	 * <li>Forbidden imports excludes regexp = "^.+Exception$"</li>
    53	 * </ul>
    54	 * <p>
    55	 * You can cover more sophisticated rules by means of few check instances.
    56	 * </p>
    57	 * @author <a href="mailto:Daniil.Yaroslavtsev@gmail.com"> Daniil
    58	 *         Yaroslavtsev</a>
    59	 */
    60	public class ForbidCertainImportsCheck extends AbstractCheck {
    61	
    62	    /**
    63	     * The key is pointing to the warning message text in "messages.properties"
    64	     * file.
    65	     */
    66	    public static final String MSG_KEY = "forbid.certain.imports";
    67	
    68	    /**
    69	     * Pattern for matching package fully qualified name
    70	     * (sets the scope of affected packages).
    71	     */
    72	    private Pattern packageNamesRegexp;
    73	
    74	    /**
    75	     * Pattern for matching forbidden imports.
    76	     */
    77	    private Pattern forbiddenImportsRegexp;
    78	
    79	    /**
    80	     * Pattern for excluding imports from checking.
    81	     */
    82	    private Pattern forbiddenImportsExcludesRegexp;
    83	
    84	    /**
    85	     * True, if currently processed package fully qualified name
    86	     * matches regexp is provided by user.
    87	     */
    88	    private boolean packageMatches;
    89	
    90	    /**
    91	     * Sets the regexp for matching package fully qualified name.
    92	     * @param packageNameRegexp
    93	     *        regexp for package fully qualified name matching.
    94	     */
    95	    public void setPackageNameRegexp(String packageNameRegexp) {
    96	        if (packageNameRegexp != null) {
    97	            packageNamesRegexp = Pattern.compile(packageNameRegexp);
    98	        }
    99	    }
   100	
   101	    /**
   102	     * Gets the regexp is used for matching forbidden imports.
   103	     * @return regexp for forbidden imports matching.
   104	     */
   105	    public String getForbiddenImportRegexp() {
   106	        return forbiddenImportsRegexp.toString();
   107	    }
   108	
   109	    /**
   110	     * Sets the regexp for matching forbidden imports.
   111	     * @param forbiddenImportsRegexp
   112	     *        regexp for matching forbidden imports.
   113	     */
   114	    public void setForbiddenImportsRegexp(String forbiddenImportsRegexp) {
   115	        if (forbiddenImportsRegexp != null) {
   116	            this.forbiddenImportsRegexp = Pattern.compile(forbiddenImportsRegexp);
   117	        }
   118	    }
   119	
   120	    /**
   121	     * Sets the regexp for excluding imports from checking.
   122	     * @param forbiddenImportsExcludesRegexp
   123	     *        String contains a regexp for excluding imports from checking.
   124	     */
   125	    public void setForbiddenImportsExcludesRegexp(String
   126	            forbiddenImportsExcludesRegexp) {
   127	        if (forbiddenImportsExcludesRegexp != null) {
   128	            this.forbiddenImportsExcludesRegexp = Pattern
   129	                    .compile(forbiddenImportsExcludesRegexp);
   130	        }
   131	    }
   132	
   133	    @Override
   134	    public int[] getDefaultTokens() {
   135	        return new int[] {
   136	            TokenTypes.PACKAGE_DEF,
   137	            TokenTypes.IMPORT,
   138	            TokenTypes.LITERAL_NEW,
   139	        };
   140	    }
   141	
   142	    @Override
   143	    public int[] getAcceptableTokens() {
   144	        return getDefaultTokens();
   145	    }
   146	
   147	    @Override
   148	    public int[] getRequiredTokens() {
   149	        return getDefaultTokens();
   150	    }
   151	
   152	    @Override
   153	    public void beginTree(DetailAST rootAST) {
   154	        packageMatches = false;
   155	    }
   156	
   157	    @Override
   158	    public void visitToken(DetailAST ast) {
   159	        switch (ast.getType()) {
   160	            case TokenTypes.PACKAGE_DEF:
   161	                if (packageNamesRegexp != null) {
   162	                    final String packageQualifiedName = getText(ast);
   163	                    packageMatches = packageNamesRegexp.matcher(packageQualifiedName)
   164	                        .matches();
   165	                }
   166	                break;
   167	            case TokenTypes.IMPORT:
   168	                final String importQualifiedText = getText(ast);
   169	                if (isImportForbidden(importQualifiedText)) {
   170	                    log(ast, importQualifiedText);
   171	                }
   172	                break;
   173	            case TokenTypes.LITERAL_NEW:
   174	                if (ast.findFirstToken(TokenTypes.DOT) != null) {
   175	                    final String classQualifiedText = getText(ast);
   176	                    if (isImportForbidden(classQualifiedText)) {
   177	                        log(ast, classQualifiedText);
   178	                    }
   179	                }
   180	                break;
   181	            default:
