   191	     *     classes package, false otherwise
   192	     */
   193	    private boolean isImportForbidden(String importText) {
   194	        return packageMatches
   195	                && forbiddenImportsRegexp != null
   196	                && forbiddenImportsRegexp.matcher(importText).matches()
   197	                && (forbiddenImportsExcludesRegexp == null
   198	                    || !forbiddenImportsExcludesRegexp.matcher(importText).matches());
   199	    }
