   201	    /**
   202	     * Logs message on the part of code.
   203	     * @param nodeToWarn
   204	     *        A DetailAST node is pointing to the part of code to warn on.
   205	     * @param importText
   206	     *        import to be warned.
   207	     */
   208	    private void log(DetailAST nodeToWarn, String importText) {
   209	        log(nodeToWarn.getLineNo(), MSG_KEY,
   210	                getForbiddenImportRegexp(), importText);
   211	    }
   212	
   213	    /**
   214	     * Gets package/import text representation from node of PACKAGE_DEF or IMPORT type.
   215	     * @param packageDefOrImportNode
   216	     *        - DetailAST node is pointing to package or import definition
   217	     *        (should be a PACKAGE_DEF or IMPORT type).
   218	     * @return The fully qualified name of package or import without
   219	     *         "package"/"import" words or semicolons.
   220	     */
   221	    private static String getText(DetailAST packageDefOrImportNode) {
   222	        String result = null;
   223	
   224	        final DetailAST identNode = packageDefOrImportNode.findFirstToken(TokenTypes.IDENT);
   225	
   226	        if (identNode == null) {
   227	            final DetailAST parentDotAST = packageDefOrImportNode.findFirstToken(TokenTypes.DOT);
   228	            final FullIdent dottedPathIdent = FullIdent
   229	                    .createFullIdentBelow(parentDotAST);
   230	            final DetailAST nameAST = parentDotAST.getLastChild();
   231	            result = dottedPathIdent.getText() + "." + nameAST.getText();
   232	        }
   233	        else {
   234	            result = identNode.getText();
   235	        }
   236	        return result;
   237	    }
