    28	/**
    29	 * <p>
    30	 * This check verifies the name of JUnit4 test class for compliance with user
    31	 * defined naming convention(by default Check expects test classes names
    32	 * matching
    33	 * ".+Test\\d*|.+Tests\\d*|Test.+|Tests.+|.+IT|.+ITs|.+TestCase\\d*|.+TestCases\\d*"
    34	 * regex).
    35	 * </p>
    36	 * <p>
    37	 * Class is considered to be a test if its definition or one of its method
    38	 * definitions annotated with user defined annotations. By default Check looks
    39	 * for classes which contain methods annotated with "Test" or "org.junit.Test".
    40	 * </p>
    41	 * <p>
    42	 * Check has following options:
    43	 * </p>
    44	 * <p>
    45	 * "expectedClassNameRegex" - regular expression which matches expected test
    46	 * class names. If test class name does not matches this regex then Check will
    47	 * log violation. This option defaults to
    48	 * ".+Test\\d*|.+Tests\\d*|Test.+|Tests.+|.+IT|.+ITs|.+TestCase\\d*|.+TestCases\\d*".
    49	 * </p>
    50	 * <p>
    51	 * "classAnnotationNameRegex" - regular expression which matches test annotation
    52	 * names on classes. If class annotated with matching annotation, it is
    53	 * considered to be a test. This option defaults to empty regex(one that matches
    54	 * nothing). If for example this option set to "RunWith", then class "SomeClass"
    55	 * is considered to be a test:
    56	 *
    57	 * <pre>
    58	 * <code>
    59	 * {@literal @}RunWith(Parameterized.class)
    60	 * class SomeClass
    61	 * {
    62	 * }
    63	 * </code>
    64	 * </pre>
    65	 *
    66	 * <p>
    67	 * "methodAnnotationNameRegex" - regular expression which matches test
    68	 * annotation names on methods. If class contains a method annotated with
    69	 * matching annotation, it is considered to be a test. This option defaults to
    70	 * "Test|org.junit.Test". For example, if this option set to "Test", then class
    71	 * "SomeClass" is considered to be a test.
    72	 *
    73	 * <pre>
    74	 * <code>
    75	 * class SomeClass
    76	 * {
    77	 *      {@literal @}Test
    78	 *      void method() {
    79	 *
    80	 *      }
    81	 * }
    82	 * </code>
    83	 * </pre>
    84	 *
    85	 * <p>
    86	 * Annotation names must be specified exactly the same way it specified in code,
    87	 * thus if Check must match annotation with fully qualified name, corresponding
    88	 * options must contain qualified annotation name and vice versa. For example,
    89	 * if annotation regex is "org.junit.Test" Check will recognize "{@literal @}
    90	 * org.junit.Test" annotation and will skip "{@literal @}Test" annotation and
    91	 * vice versa if annotation regex is "Test" Check will recognize "{@literal @}
    92	 * Test" annotation and skip "{@literal @}org.junit.Test" annotation.
    93	 * </p>
    94	 * <p>
    95	 * Following configuration will adjust Check to look for classes annotated with
    96	 * annotation "RunWith" or classes with methods annotated with "Test" and verify
    97	 * that classes names end with "Test" or "Tests".
    98	 *
    99	 * <pre>
   100	 *     &lt;module name="NameConventionForJUnit4TestClassesCheck"&gt;
   101	 *       &lt;property name="expectedClassNameRegex" value=".+Tests|.+Test"/&gt;
   102	 *       &lt;property name="classAnnotationNameRegex" value="RunWith"/&gt;
   103	 *       &lt;property name="methodAnnotationNameRegex" value="Test"/&gt;
   104	 *     &lt;/module&gt;
   105	 * </pre>
   106	 *
   107	 * @author <a href="mailto:zuy_alexey@mail.ru">Zuy Alexey</a>
   108	 */
   109	public class NameConventionForJunit4TestClassesCheck extends AbstractCheck {
   110	
   111	    /**
   112	     * Violation message key.
   113	     */
   114	    public static final String MSG_KEY = "name.convention.for.test.classes";
   115	
   116	    /**
   117	     * <p>
   118	     * Regular expression which matches expected names of JUnit test classes.
   119	     * </p>
   120	     * <p>
   121	     * Default value is
   122	     * ".+Test\\d*|.+Tests\\d*|Test.+|Tests.+|.+IT|.+ITs|.+TestCase\\d*|.+TestCases\\d*".
   123	     * </p>
   124	     */
   125	    private Pattern expectedClassNameRegex =
   126	            Pattern.compile(".+Test\\d*|.+Tests\\d*|Test.+|Tests.+|.+IT|.+ITs|.+TestCase\\d*"
   127	                    + "|.+TestCases\\d*");
   128	
   129	    /**
   130	     * <p>
   131	     * Regular expression which matches JUnit class test annotation names.
   132	     * </p>
   133	     * <p>
   134	     * By default this regex is empty.
   135	     * </p>
   136	     */
   137	    private Pattern classAnnotationNameRegex;
   138	
   139	    /**
   140	     * <p>
   141	     * Regular expression which matches JUnit method test annotation names.
   142	     * </p>
   143	     * <p>
   144	     * Default value is "Test|org.junit.Test".
   145	     * </p>
   146	     */
   147	    private Pattern methodAnnotationNameRegex =
   148	            Pattern.compile("Test|org.junit.Test");
   149	
   150	    /**
   151	     * Sets regexp to match 'expected' class names for JUnit tests.
   152	     * @param expectedClassNameRegex
   153	     *        regexp to match 'correct' JUnit test class names.
   154	     */
   155	    public void setExpectedClassNameRegex(String expectedClassNameRegex) {
   156	        if (expectedClassNameRegex != null && !expectedClassNameRegex.isEmpty()) {
   157	            this.expectedClassNameRegex = Pattern.compile(expectedClassNameRegex);
   158	        }
   159	        else {
   160	            this.expectedClassNameRegex = null;
   161	        }
   162	    }
   163	
   164	    /**
   165	     * Sets class test annotation name regexp for JUnit tests.
   166	     * @param annotationNameRegex
   167	     *        regexp to match annotations for unit test classes.
   168	     */
   169	    public void setClassAnnotationNameRegex(String annotationNameRegex) {
   170	        if (annotationNameRegex != null && !annotationNameRegex.isEmpty()) {
   171	            classAnnotationNameRegex = Pattern.compile(annotationNameRegex);
   172	        }
   173	        else {
   174	            classAnnotationNameRegex = null;
   175	        }
   176	    }
   177	
   178	    /**
   179	     * Sets method test annotation name regexp for JUnit tests.
   180	     * @param annotationNameRegex
   181	     *        regexp to match annotations for unit test classes.
   182	     */
   183	    public void setMethodAnnotationNameRegex(String annotationNameRegex) {
   184	        if (annotationNameRegex != null && !annotationNameRegex.isEmpty()) {
   185	            methodAnnotationNameRegex = Pattern.compile(annotationNameRegex);
   186	        }
   187	        else {
   188	            methodAnnotationNameRegex = null;
   189	        }
   190	    }
