   193	    public int[] getDefaultTokens() {
   194	        return new int[] {
   195	            TokenTypes.CLASS_DEF,
   196	        };
   197	    }
   198	
   199	    @Override
   200	    public int[] getAcceptableTokens() {
   201	        return getDefaultTokens();
   202	    }
