   209	    @Override
   210	    public void visitToken(DetailAST classDefNode) {
   211	        if ((isClassDefinitionAnnotated(classDefNode) || isAtleastOneMethodAnnotated(classDefNode))
   212	                && hasUnexpectedName(classDefNode)) {
   213	            logUnexpectedClassName(classDefNode);
   214	        }
   215	    }
   216	
   217	    /**
   218	     * Checks whether class definition annotated with user defined annotation.
   219	     * @param classDefNode
   220	     *        a class definition node
   221	     * @return true, if class definition annotated with user defined annotation
   222	     */
   223	    private boolean isClassDefinitionAnnotated(DetailAST classDefNode) {
   224	        return hasAnnotation(classDefNode, classAnnotationNameRegex);
   225	    }
   226	
   227	    /**
   228	     * Checks whether class contains at least one method annotated with user
   229	     * defined annotation.
   230	     * @param classDefNode
   231	     *        a class definition node
   232	     * @return true, if class contains at least one method annotated with user
   233	     *         defined annotation
   234	     */
   235	    private boolean isAtleastOneMethodAnnotated(DetailAST classDefNode) {
   236	        boolean result = false;
   237	        DetailAST classMemberNode =
   238	                classDefNode.findFirstToken(TokenTypes.OBJBLOCK).getFirstChild();
   239	
   240	        while (classMemberNode != null) {
   241	            if (classMemberNode.getType() == TokenTypes.METHOD_DEF
   242	                    && hasAnnotation(classMemberNode, methodAnnotationNameRegex)) {
   243	                result = true;
   244	                break;
   245	            }
   246	
   247	            classMemberNode = classMemberNode.getNextSibling();
   248	        }
   249	
   250	        return result;
   251	    }
   252	
   253	    /**
   254	     * Returns true, if class has unexpected name.
   255	     * @param classDefNode
   256	     *        a class definition node
   257	     * @return true, if class has unexpected name
   258	     */
   259	    private boolean hasUnexpectedName(final DetailAST classDefNode) {
   260	        final String className = getIdentifierName(classDefNode);
   261	        return !isMatchesRegex(expectedClassNameRegex, className);
   262	    }
   263	
   264	    /**
   265	     * Returns true, if class or method has annotation with name specified in
   266	     * regexp.
   267	     * @param methodOrClassDefNode
   268	     *        the node of type TokenTypes.METHOD_DEF or TokenTypes.CLASS_DEF
   269	     * @param annotationNamesRegexp
   270	     *        regexp contains annotation names
   271	     * @return true, if the class or method contains one of the annotations,
   272	     *         specified in the regexp
   273	     */
   274	    private static boolean hasAnnotation(DetailAST methodOrClassDefNode,
   275	            Pattern annotationNamesRegexp) {
   276	        DetailAST modifierNode =
   277	                methodOrClassDefNode.findFirstToken(TokenTypes.MODIFIERS).getFirstChild();
   278	
   279	        boolean result = false;
   280	
   281	        while (modifierNode != null) {
   282	            if (modifierNode.getType() == TokenTypes.ANNOTATION) {
   283	                final String annotationName = getIdentifierName(modifierNode);
   284	
   285	                if (isMatchesRegex(annotationNamesRegexp, annotationName)) {
   286	                    result = true;
   287	                    break;
   288	                }
   289	            }
   290	
   291	            modifierNode = modifierNode.getNextSibling();
   292	        }
   293	
   294	        return result;
   295	    }
   296	
   297	    /**
   298	     * Logs unexpected class name.
   299	     * @param classDef
   300	     *        the node of type TokenTypes.CLASS_DEF
   301	     */
   302	    private void logUnexpectedClassName(DetailAST classDef) {
   303	        log(classDef.findFirstToken(TokenTypes.IDENT), MSG_KEY, expectedClassNameRegex);
   304	    }
   305	
   306	    /**
   307	     * Returns name of identifier contained in specified node.
   308	     * @param identifierNode
   309	     *        a node containing identifier or qualified identifier.
   310	     * @return identifier name for specified node. If node contains qualified
   311	     *         name then method returns its text representation.
   312	     */
   313	    private static String getIdentifierName(DetailAST identifierNode) {
   314	        final DetailAST identNode = identifierNode.findFirstToken(TokenTypes.IDENT);
   315	        String result;
   316	
   317	        if (identNode != null) {
   318	            result = identNode.getText();
   319	        }
   320	        else {
   321	            result = "";
   322	
   323	            DetailAST node = identifierNode.findFirstToken(TokenTypes.DOT);
   324	
   325	            while (node.getType() == TokenTypes.DOT) {
   326	                result = "." + node.getLastChild().getText() + result;
   327	
   328	                node = node.getFirstChild();
   329	            }
   330	
   331	            result = node.getText() + result;
   332	        }
   333	
   334	        return result;
   335	    }
