   337	    /**
   338	     * Matches string against regexp.
   339	     * @param regexPattern
   340	     *        regex to match string with. May be null.
   341	     * @param str
   342	     *        a string to match against regex.
   343	     * @return false if regex is null, otherwise result of matching string
   344	     *         against regex.
   345	     */
   346	    private static boolean isMatchesRegex(Pattern regexPattern, String str) {
   347	        final boolean result;
   348	        if (regexPattern != null) {
   349	            result = regexPattern.matcher(str).matches();
   350	        }
   351	        else {
   352	            result = false;
   353	        }
   354	        return result;
   355	    }
